// 테마별 어휘 덱 (themed vocabulary decks). Hand-authored N5/N4 vocabulary
// grouped by everyday theme. All data is static (no network). Each word carries
// its own furigana tokens ({b} base, optional {r} reading over kanji) so the
// FuriganaTokens component can render readings without going through the i18n
// phrase table. Readings are kana glosses; meanings are Korean.

export type VocabWord = {
  wordJa: string; // headword as written (for TTS)
  tokens: { b: string; r?: string }[]; // furigana render tokens
  reading: string; // full kana reading
  meaningKo: string; // Korean meaning
  exampleJa?: string; // short example sentence
  exampleKo?: string; // Korean gloss of the example
};

export type VocabDeck = {
  id: string;
  title: string; // Korean deck name
  emoji: string;
  descKo: string; // one-line Korean description
  words: VocabWord[];
};

