export const deckById = (id: string): VocabDeck | undefined => DECKS.find((d) => d.id === id);

// Total hand-authored words across all decks (111 decks, 1833 words), computed at load.
export const VOCAB_TOTAL = DECKS.reduce((n, d) => n + d.words.length, 0);
